form:Form.form:Scripts:
		function LoadForm() 
{    
	if (Ctrl('main').GetMode()=="NEW")
	{
		Ctrl('c_estado').SetCValue("abi");							
		CtrlEnabled('c_estado', false);		
	}
	if (Ctrl('main').GetMode()=="LIST")
		ChangeSelect(Ctrl('LIST'));

	if (Ctrl('main').GetMode()=="SHOW" || Ctrl('main').GetMode()=="EDIT")
	{	 
		if (Ctrl('c_estado').GetCValue() == "abi") 
		{  
			CtrlEnabled('f_fechainicio', true);
			CtrlEnabled('f_fechafin', true);						
			CtrlEnabled('PROCESAR', false);
			CtrlEnabled('CERRAR', false); 		
			CtrlEnabled('oi_empresa', true);		
			CtrlEnabled('DELETE', true);
			CtrlEnabled('LIQUIDACIONPERS', false);
			CtrlEnabled('LEGAJOS', true);
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', false);
		}

		if (Ctrl('c_estado').GetCValue() == "ini") 
		{  
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', true);
			CtrlEnabled('CERRAR', false); 		
			CtrlEnabled('oi_empresa', false);		
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);
			CtrlEnabled('LEGAJOS', true);
			CtrlEnabled('CONGELAR', false); 
			CtrlEnabled('DESCONGELAR', false);
		}

		if (Ctrl('c_estado').GetCValue() == "pro") 
		{  
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', true);
			CtrlEnabled('CERRAR', true); 		
			CtrlEnabled('oi_empresa', false);		
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);
			CtrlEnabled('LEGAJOS', true);
			CtrlEnabled('CONGELAR', true);
			CtrlEnabled('DESCONGELAR', false);        		
		}  

		if (Ctrl('c_estado').GetCValue() == "cer") 
		{ 		
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', false);  
			CtrlEnabled('EDIT', false);  		
			CtrlEnabled('CERRAR', false);			 
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);   
			CtrlEnabled('LEGAJOS', false);
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', false);
		}  
		if (Ctrl('c_estado').GetCValue() == "con") 
		{  
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', false);
			CtrlEnabled('CERRAR', false); 		
			CtrlEnabled('oi_empresa', false);		
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);
			CtrlEnabled('LEGAJOS', false);
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', true);        		
		}
	}   
}	

function ChangeSelect(lvObj)
{
	if (lvObj.GetSelectAttrValue("c_estado")=="abi")
	{ 			
			CtrlEnabled('PROCESAR', false);
			CtrlEnabled('CERRAR', false); 		
			CtrlEnabled('oi_empresa', true);		
			CtrlEnabled('DELETE', true);
			CtrlEnabled('LIQUIDACIONPERS', false);
			CtrlEnabled('LEGAJOS', true);
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', false); 			
	}

	if (lvObj.GetSelectAttrValue("c_estado")=="ini")
	{
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', true);
			CtrlEnabled('CERRAR', false); 		
			CtrlEnabled('oi_empresa', false);		
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);
			CtrlEnabled('LEGAJOS', true); 
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', false); 			
	}

	if (lvObj.GetSelectAttrValue("c_estado")=="pro")
	{
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', true);
			CtrlEnabled('CERRAR', true); 		
			CtrlEnabled('oi_empresa', false);		
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);
			CtrlEnabled('LEGAJOS', true);
			CtrlEnabled('CONGELAR', true);
			CtrlEnabled('DESCONGELAR', false);  
	}

	if (lvObj.GetSelectAttrValue("c_estado")=="cer")
	{
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', false);  
			CtrlEnabled('EDIT', false);  		
			CtrlEnabled('CERRAR', false);			 
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);   
			CtrlEnabled('LEGAJOS', false); 
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', false); 
	}
	if (lvObj.GetSelectAttrValue("c_estado")=="con")
	{
			CtrlEnabled('f_fechainicio', false);
			CtrlEnabled('f_fechafin', false);						
			CtrlEnabled('PROCESAR', false);  
			CtrlEnabled('EDIT', false);  		
			CtrlEnabled('CERRAR', false);			 
			CtrlEnabled('DELETE', false);
			CtrlEnabled('LIQUIDACIONPERS', true);   
			CtrlEnabled('LEGAJOS', false); 
			CtrlEnabled('CONGELAR', false);
			CtrlEnabled('DESCONGELAR', true); 
	}
}	

function VALIDARRANGOFECHA()
{    
	if ( Ctrl("f_fechainicio").TypedValue() > Ctrl("f_fechafin").TypedValue())
	{
		alert('La fecha de inicio es mayor que la fecha de fin');
		return false;						
	}					
	else return true;													
}            

function CONGELAR()
{ 
	if (confirm("¿Está seguro que desea congelar el procesamiento?"))
	{		
		return true;
	}
	else
	{		
		return false;
	}	
}


function DESCONGELAR()
{ 
	if (confirm("¿Está seguro que desea descongelar el procesamiento?"))
	{
		return true;
	}
	else
	{
		return false;
	}	
}
